Platform API Routes
===================
Auth, Airdrop, Forum, and Education routes
"""
from fastapi import APIRouter, HTTPException, Depends, Header, Request
from typing import Optional, List, Dict, Any
import sys

sys.path.insert(0, '/root/rmi/backend')
from services.auth_service import auth_service
from services.airdrop_service import airdrop_service
from services.forum_service import forum_service
from services.education_service import education_service

router = APIRouter(prefix="/platform", tags=["Platform"])

# ==========================================
# AUTHENTICATION
# ==========================================

@router.post("/auth/google")
async def auth_google(token: str):
    """Authenticate with Google"""
    try:
        # Verify Google token
        google_data = await auth_service.verify_google_token(token)
        if not google_data:
            raise HTTPException(status_code=401, detail="Invalid Google token")

        # Get or create user
        result = await auth_service.get_or_create_user(
            auth_provider="google",
            provider_id=google_data["provider_id"],
            email=google_data.get("email"),
            username=google_data.get("username"),
            display_name=google_data.get("display_name"),
            avatar_url=google_data.get("avatar_url")
        )

        # Create session
        access_token = auth_service.create_access_token(result["user"]["id"])

        return {
            "success": True,
            "is_new": result["is_new"],
            "user": result["user"],
            "token": access_token
        }
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))


@router.post("/auth/twitter")
async def auth_twitter(access_token: str):
    """Authenticate with Twitter/X"""
    try:
        twitter_data = await auth_service.verify_twitter_token(access_token)
        if not twitter_data:
            raise HTTPException(status_code=401, detail="Invalid Twitter token")

        result = await auth_service.get_or_create_user(
            auth_provider="twitter",
            provider_id=twitter_data["provider_id"],
            username=twitter_data.get("username"),
            display_name=twitter_data.get("display_name"),
            avatar_url=twitter_data.get("avatar_url")
        )

        access_token = auth_service.create_access_token(result["user"]["id"])

        return {
            "success": True,
            "is_new": result["is_new"],
            "user": result["user"],
            "token": access_token
        }
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))


@router.post("/auth/privy")
async def auth_privy(token: str):
    """Authenticate with Privy (Web3 wallet)"""
    try:
        privy_data = await auth_service.verify_privy_token(token)
        if not privy_data:
            raise HTTPException(status_code=401, detail="Invalid Privy token")

        result = await auth_service.get_or_create_user(
            auth_provider="privy",
            provider_id=privy_data["provider_id"],
            email=privy_data.get("email"),
            wallet_address=privy_data.get("wallet_address")
        )

        # Link wallet if provided
        if privy_data.get("wallet_address") and result["is_new"]:
            await auth_service.link_wallet_to_user(
                result["user"]["id"],
